mapper.select:
SELECT hp.HOMPI_ID, hp.HOMPI_URL, hp.HOMPI_TITLE, hp.OWNER_USER_ID, hds.TODAY_CNT, hp.TOTAL_CNT
FROM HOMPI hp
INNER JOIN HOMPI_DAILY_STATS hds ON hp.HOMPI_ID = hds.HOMPI_ID
WHERE 1 = 1
AND hds.DAY_STATS_DATE = CURDATE()

    AND hp.HOMPI_ID = #{hompiId}
    AND hp.OWNER_USER_ID = #{userId}


    AND hp.HOMPI_ID = #{hompiId}
